// Dynamically aggregate all important news into the 'important' channel
const allImportantNews: NewsItem[] = [];
rawChannels.forEach(channel => {
    channel.news.forEach(news => {
        if (news.type === 'important' || news.type === 'important_mandatory') {
            // Check if already added (from the 'important' template itself)
            if (!allImportantNews.some(n => n.title === news.title)) {
                allImportantNews.push({...news});
            }
        }
    });
});

// Update the 'important' channel
const importantChannel = rawChannels.find(c => c.id === 'important');
if (importantChannel) {
    importantChannel.news = allImportantNews;
    const latest = allImportantNews[allImportantNews.length - 1];
    if (latest) {
        importantChannel.lastMessage = latest.title;
        importantChannel.lastMessageContent = latest.content;
        importantChannel.lastNewsId = latest.id;
    }
}

